async function verify2({ signingKey, timestamp, token, signature }) {
  const encoder = new TextEncoder();
  const keyData = encoder.encode(signingKey);
  const message = encoder.encode(timestamp + token);
  const key = await crypto.subtle.importKey(
    "raw",
    keyData,
    { name: "HMAC", hash: "SHA-256" },
    false,
    ["sign"]
  );
  const signatureBuffer = await crypto.subtle.sign(
    "HMAC",
    key,
    message
  );
  const signatureArray = Array.from(new Uint8Array(signatureBuffer));
  const encodedToken = signatureArray.map((b) => b.toString(16).padStart(2, "0")).join("");
  return encodedToken === signature;
}

// ../teenybase/src/worker/util/replaceTemplateVariables.ts
function replaceTemplateVariables(html3, variables, times = 1) {
  if (!html3 || !times) return html3;
  let res = html3.replace(/\{\{(.*?)}}/g, (match2, p1) => {
    const split = p1.split("|");
    const key = split[0]?.trim() || "";
    const def = split.slice(1).join("|").trim() || "";
    return (variables[key] || def) + "";
  });
  if (times > 1 && res.search(/\{\{(.*?)}}/)) res = replaceTemplateVariables(res, variables, times - 1);
  return res;
}

